#include <stdio.h>
#include <unistd.h>
#include <getopt.h>
#include <stdlib.h>
#include <assert.h>
#include <cuda_runtime.h>

#include "common.h"

#include <string.h>
#include <string>

#ifdef RD_WG_SIZE_0_0
        #define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
        #define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
        #define BLOCK_SIZE RD_WG_SIZE
#else
        #define BLOCK_SIZE 16
#endif

extern __global__ void lud_diagonal(float *m, int matrix_dim, int offset);
extern __global__ void lud_perimeter(float *m, int matrix_dim, int offset);
extern __global__ void lud_internal(float *m, int matrix_dim, int offset);

static int do_verify = 0;

static struct option long_options[] = {
      {"input", 1, NULL, 'i'},
      {"size", 1, NULL, 's'},
      {"verify", 0, NULL, 'v'},
      {"platform", 1, NULL, 'p'},
      {"device", 1, NULL, 'd'},
      {0,0,0,0}
};

int
main ( int argc, char *argv[] )
{
#ifdef TIMING
    struct timeval tv;
    struct timeval tv_total_start;
    struct timeval tv_init_end;
    struct timeval tv_mem_alloc_end;
    struct timeval tv_close_start, tv_close_end;
    float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
          d2h_time = 0, close_time = 0, total_time = 0;
#endif

    printf("WG size of kernel = %d X %d\n", BLOCK_SIZE, BLOCK_SIZE);
    size_t matrix_dim = 32; 
    int opt, option_index=0;
    func_ret_t ret;
    const char *input_file = NULL;
    float *m, *mm;
    stopwatch sw;
    int platform_id_inuse = 0;
    int device_id_inuse = 0;

    while ((opt = getopt_long(argc, argv, "::vs:i:p:d:", 
                            long_options, &option_index)) != -1 ) {
        switch(opt){
            case 'i':
            input_file = optarg;
            break;
            case 'v':
            do_verify = 1;
            break;
        case 's':
            matrix_dim = atoi(optarg);
            printf("Generate input matrix internally, size =%lu\n", matrix_dim);
            break;
        case 'p':
            platform_id_inuse = atoi(optarg);
            break;
        case 'd':
            device_id_inuse = atoi(optarg);
            break;
        case '?':
            fprintf(stderr, "invalid option\n");
            break;
        case ':':
            fprintf(stderr, "missing argument\n");
            break;
        default:
            fprintf(stderr, "Usage: %s [-v] [-s matrix_size|-i input_file]\n",
                  argv[0]);
            exit(EXIT_FAILURE);
        }
    }

    if ( (optind < argc) || (optind == 1)) {
        fprintf(stderr, "Usage: %s [-v] [-s matrix_size|-i input_file]\n", argv[0]);
        exit(EXIT_FAILURE);
    }	

    if (input_file) {
        printf("Reading matrix from file %s\n", input_file);
        ret = create_matrix_from_file(&m, input_file, &matrix_dim);
        if (ret != RET_SUCCESS) {
            m = NULL;
            fprintf(stderr, "error create matrix from file %s\n", input_file);
            exit(EXIT_FAILURE);
        }
    } 

    else if (matrix_dim) {
      printf("Creating matrix internally size=%lu\n", matrix_dim);
      ret = create_matrix(&m, matrix_dim);
      if (ret != RET_SUCCESS) {
        m = NULL;
        fprintf(stderr, "error create matrix internally size=%lu\n", matrix_dim);
        exit(EXIT_FAILURE);
      }
    }

    else {
      printf("No input file specified!\n");
      exit(EXIT_FAILURE);
    }

    if (do_verify){
        printf("Before LUD\n");

        matrix_duplicate(m, &mm, matrix_dim);
    }

#ifdef  TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

    cudaError_t err = cudaSuccess;
#ifdef  TIMING
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    float *d_m;
    err = cudaMalloc(&d_m, matrix_dim*matrix_dim * sizeof(float));
    if(err != cudaSuccess) { printf("ERROR: cudaMalloc d_m (size:%lu) => %d\n", matrix_dim*matrix_dim, err); return -1;} 
#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_init_end, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    stopwatch_start(&sw);
    cudaEvent_t h2d_event;
    cudaEventCreate(&h2d_event);
    err = cudaMemcpy(d_m, m, matrix_dim*matrix_dim*sizeof(float), cudaMemcpyHostToDevice);
    if(err != cudaSuccess) { printf("ERROR: cudaMemcpy d_m (size:%lu) => %d\n", matrix_dim*matrix_dim, err); return -1; }
    cudaEventRecord(h2d_event, 0);
#ifdef TIMING
    cudaEventSynchronize(h2d_event);
    float h2d_ms;
    cudaEventElapsedTime(&h2d_ms, h2d_event);
    h2d_time = h2d_ms;
#endif
    cudaEventDestroy(h2d_event);

    size_t i=0;
    for (i=0; i < matrix_dim-BLOCK_SIZE; i += BLOCK_SIZE) {

      dim3 block1(BLOCK_SIZE, 1, 1);
      dim3 grid1(1, 1, 1);

      cudaEvent_t kernel_event1;
      cudaEventCreate(&kernel_event1);
      lud_diagonal<<<grid1, block1>>>(d_m, matrix_dim, i);
      cudaEventRecord(kernel_event1, 0);
      err = cudaGetLastError();
      if(err != cudaSuccess) { printf("ERROR: diagnal kernel =>%d failed\n", err); return -1; }	
#ifdef TIMING
      cudaEventSynchronize(kernel_event1);
      float kernel_ms1;
      cudaEventElapsedTime(&kernel_ms1, kernel_event1);
      kernel_time += kernel_ms1;
#endif
      cudaEventDestroy(kernel_event1);

      dim3 block2(BLOCK_SIZE * 2, 1, 1);
      dim3 grid2((matrix_dim-i)/BLOCK_SIZE-1, 1, 1);

      if (grid2.x > 0) {
          cudaEvent_t kernel_event2;
          cudaEventCreate(&kernel_event2);
          lud_perimeter<<<grid2, block2>>>(d_m, matrix_dim, i);
          cudaEventRecord(kernel_event2, 0);
          err = cudaGetLastError();
          if(err != cudaSuccess) { printf("ERROR: perimeter kernel =>%d failed\n", err); return -1; }	
#ifdef TIMING
          cudaEventSynchronize(kernel_event2);
          float kernel_ms2;
          cudaEventElapsedTime(&kernel_ms2, kernel_event2);
          kernel_time += kernel_ms2;
#endif
          cudaEventDestroy(kernel_event2);
      }

      dim3 block3(BLOCK_SIZE, BLOCK_SIZE, 1);
      dim3 grid3((matrix_dim-i)/BLOCK_SIZE-1, (matrix_dim-i)/BLOCK_SIZE-1, 1);

      if (grid3.x > 0) {
          cudaEvent_t kernel_event3;
          cudaEventCreate(&kernel_event3);
          lud_internal<<<grid3, block3>>>(d_m, matrix_dim, i);
          cudaEventRecord(kernel_event3, 0);
          err = cudaGetLastError();
          if(err != cudaSuccess) { printf("ERROR: internal kernel =>%d failed\n", err); return -1; }	
#ifdef TIMING
          cudaEventSynchronize(kernel_event3);
          float kernel_ms3;
          cudaEventElapsedTime(&kernel_ms3, kernel_event3);
          kernel_time += kernel_ms3;
#endif
          cudaEventDestroy(kernel_event3);
      }
    }

    dim3 block1(BLOCK_SIZE, 1, 1);
    dim3 grid1(1, 1, 1);
    cudaEvent_t kernel_event4;
    cudaEventCreate(&kernel_event4);
    lud_diagonal<<<grid1, block1>>>(d_m, matrix_dim, i);
    cudaEventRecord(kernel_event4, 0);
    err = cudaGetLastError();
    if(err != cudaSuccess) { printf("ERROR: diagnal kernel =>%d failed\n", err); return -1; }	
#ifdef TIMING
    cudaEventSynchronize(kernel_event4);
    float kernel_ms4;
    cudaEventElapsedTime(&kernel_ms4, kernel_event4);
    kernel_time += kernel_ms4;
#endif
    cudaEventDestroy(kernel_event4);

    cudaDeviceSynchronize();
    cudaEvent_t d2h_event;
    cudaEventCreate(&d2h_event);
    err = cudaMemcpy(m, d_m, matrix_dim*matrix_dim*sizeof(float), cudaMemcpyDeviceToHost);
    if(err != cudaSuccess) { printf("ERROR: cudaMemcpy d_m (size:%lu) => %d\n", matrix_dim*matrix_dim, err); return -1; }
    cudaEventRecord(d2h_event, 0);
#ifdef TIMING
    cudaEventSynchronize(d2h_event);
    float d2h_ms;
    cudaEventElapsedTime(&d2h_ms, d2h_event);
    d2h_time = d2h_ms;
#endif
    cudaEventDestroy(d2h_event);

    cudaDeviceSynchronize();

#ifdef  TIMING
    gettimeofday(&tv_close_start, NULL);
#endif
    cudaFree(d_m);
#ifdef  TIMING
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif

    if (do_verify){
        printf("After LUD\n");

        printf(">>>Verify<<<<\n");
        lud_verify(mm, m, matrix_dim); 
        free(mm);
    }

    free(m);

    return 0;
}
